import{_ as r,o as a,c as o,a2 as t}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Theme Breadcrumbs","description":"Spinoko Theme Breadcrumbs","frontmatter":{"title":"Theme Breadcrumbs","description":"Spinoko Theme Breadcrumbs","weight":140,"extra":{"order":140},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/breadcrumbs"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/breadcrumbs"}],["meta",{"property":"og:title","content":"Theme Breadcrumbs"}],["meta",{"property":"og:description","content":"Spinoko Theme Breadcrumbs"}],["meta",{"name":"twitter:title","content":"Theme Breadcrumbs"}],["meta",{"name":"twitter:description","content":"Spinoko Theme Breadcrumbs"}]]},"headers":[],"relativePath":"docs/spinoko/breadcrumbs.md","filePath":"docs/spinoko/breadcrumbs.md"}'),s={name:"docs/spinoko/breadcrumbs.md"};function n(c,e,i,d,m,b){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="spinoko-breadcrumbs" tabindex="-1">Spinoko Breadcrumbs <a class="header-anchor" href="#spinoko-breadcrumbs" aria-label="Permalink to &quot;Spinoko Breadcrumbs&quot;">​</a></h1><p>Spinoko theme comes with automatic breadcrumbs integration since version 2.7.3. Supported SEO Plugins are Yoast SEO, Rank Math SEO, All in One SEO.</p><hr><h3 id="enable-breadcrumbs" tabindex="-1">Enable Breadcrumbs <a class="header-anchor" href="#enable-breadcrumbs" aria-label="Permalink to &quot;Enable Breadcrumbs&quot;">​</a></h3><p>To add breadcrumbs to your website you need to enable them. In your WordPress dashboard visit <strong>Appearance</strong> → <strong>Customizer</strong> → <strong>Miscellaneous Options</strong> to enable breadcrumbs as well as adjust settings.</p><h3 id="breadcrumbs-options" tabindex="-1">Breadcrumbs Options <a class="header-anchor" href="#breadcrumbs-options" aria-label="Permalink to &quot;Breadcrumbs Options&quot;">​</a></h3><p>All breadcrumbs options such as separator character, etc. should be configured in SEO plugin settings.</p><p>If you want to separate the breadcrumbs section from the content area, in Customizer you can enable an option to add a background color to it.</p>',8)])])}const l=r(s,[["render",n]]);export{p as __pageData,l as default};
